predicate IsPalindrome(word: seq<char>)
{
  forall i :: 0 <= i < |word| ==> word[i] == word[|word| - 1 - i]
}

predicate SubstringAt(text: seq<char>, sub: seq<char>, start: int)
{
  0 <= start &&
  start + |sub| <= |text| &&
  sub == text[start .. start + |sub|]
}

predicate IsSubstring(text: seq<char>, sub: seq<char>)
{
  exists start :: 0 <= start <= |text| - |sub| && SubstringAt(text, sub, start)
}

predicate PalindromicSubstringAt(s: seq<char>, start: int, len: int)
{
  0 <= start < |s| &&
  0 <= len <= |s| &&
  start + len <= |s| &&
  IsPalindrome(s[start..start+len])
}

predicate longest_palindromic_substringPost(s: seq<char>, result: seq<char>)
{
  |result| >= 1
  && IsSubstring(s, result)
  && IsPalindrome(result)
  && (forall start, len ::
      0 <= start < |s| && 0 <= len <= |s| &&
      PalindromicSubstringAt(s, start, len) ==> len <= |result|)
}

// Lemma: a single character is a palindrome
lemma singleCharPalindrome(s: seq<char>, i: int)
  requires 0 <= i < |s|
  ensures IsPalindrome(s[i..i+1])
{
  var w := s[i..i+1];
  assert |w| == 1;
}

// Lemma: a sequence of identical characters is a palindrome
lemma identicalCharsPalindrome(s: seq<char>, l: int, r: int)
  requires 0 <= l <= r < |s|
  requires forall k :: l <= k <= r ==> s[k] == s[l]
  ensures IsPalindrome(s[l..r+1])
{
  var w := s[l..r+1];
  forall i | 0 <= i < |w|
    ensures w[i] == w[|w| - 1 - i]
  {
    assert w[i] == s[l + i];
    assert w[|w| - 1 - i] == s[l + (|w| - 1 - i)];
    assert l <= l + i <= r;
    assert l <= l + (|w| - 1 - i) <= r;
  }
}

// Lemma: if s[l..r+1] is a palindrome and s[l-1] == s[r+1], then s[l-1..r+2] is a palindrome
lemma expandPalindrome(s: seq<char>, l: int, r: int)
  requires 0 < l <= r < |s| - 1
  requires IsPalindrome(s[l..r+1])
  requires s[l-1] == s[r+1]
  ensures IsPalindrome(s[l-1..r+2])
{
  var oldW := s[l..r+1];
  var newW := s[l-1..r+2];
  assert |newW| == |oldW| + 2;

  forall i | 0 <= i < |newW|
    ensures newW[i] == newW[|newW| - 1 - i]
  {
    if i == 0 {
      assert newW[0] == s[l-1];
      assert newW[|newW| - 1] == s[r+1];
    } else if i == |newW| - 1 {
      assert newW[|newW| - 1] == s[r+1];
      assert newW[0] == s[l-1];
    } else {
      // i is in range 1..|newW|-1, so it corresponds to oldW[i-1]
      assert newW[i] == s[l - 1 + i] == oldW[i - 1];
      assert newW[|newW| - 1 - i] == s[l - 1 + |newW| - 1 - i] == oldW[|newW| - 2 - i];
      assert |newW| - 2 - i == |oldW| - 1 - (i - 1);
      assert oldW[i-1] == oldW[|oldW| - 1 - (i-1)];
    }
  }
}

// Lemma: substring witness for IsSubstring
lemma substringWitness(s: seq<char>, start: int, len: int)
  requires 0 <= start
  requires start + len <= |s|
  requires len >= 0
  ensures SubstringAt(s, s[start..start+len], start)
  ensures IsSubstring(s, s[start..start+len])
{
  assert s[start..start+len] == s[start..start+len];
  assert SubstringAt(s, s[start..start+len], start);
}

// Key lemma: every palindrome has a "center" which is a maximal run of identical characters.
// Specifically, for any palindrome s[st..st+len], there exists a center index c in [st..st+len-1]
// such that the palindrome can be built by expanding from a run of identical characters containing c.
//
// We prove the contrapositive approach: the algorithm finds the longest palindrome.
// Instead, let's prove that every palindromic substring is bounded by what the algorithm finds.
//
// Actually, let's take a simpler approach: prove the algorithm correct with a
// ghost variable tracking which palindromes have been "dominated".

method longest_palindromic_substring(s: seq<char>) returns (result: seq<char>)
  requires |s| >= 1
  ensures  longest_palindromic_substringPost(s, result)
{
    var n := |s|;
    if n == 0 {
        return [];
    }

    var start := 0;
    var maxLength := 1;

    singleCharPalindrome(s, 0);
    substringWitness(s, 0, 1);

    var i := 0;

    while i < n
      invariant 0 <= i <= n
      invariant 0 <= start
      invariant start + maxLength <= n
      invariant maxLength >= 1
      invariant IsPalindrome(s[start..start+maxLength])
      invariant IsSubstring(s, s[start..start+maxLength])
      // Optimality: all palindromic substrings starting at positions < i are bounded
      // More precisely: for any palindromic substring s[st..st+len] where the "center run"
      // starts at some position < i, we have len <= maxLength.
      // We'll use a simpler formulation: all palindromes whose center is in [0..i) are bounded.
      // But this is complex. Let's use a different ghost approach.
      //
      // Ghost: track which starting positions have been fully explored
      invariant forall st, len ::
        0 <= st < |s| && 0 <= len <= |s| && st + len <= |s| && st + len <= i &&
        IsPalindrome(s[st..st+len]) ==> len <= maxLength
      // Also palindromes that start before i but extend beyond:
      // This is harder. Let me think of a different invariant.
      //
      // Actually, the key insight: after processing center i, all palindromes whose
      // rightmost center character is <= i have been considered.
      // But the outer loop variable i gets modified inside the loop (i := r, then i := i+1),
      // making this tricky.
      //
      // Let me try: all palindromes that are entirely within s[0..i] have been dominated.
    {
        var l := i;
        var r := i;

        // Expand for identical characters
        while r < n - 1 && s[r] == s[r + 1]
          invariant i <= r < n
          invariant l == i
          invariant forall k :: i <= k <= r ==> s[k] == s[i]
        {
            r := r + 1;
        }

        // Now s[i..r+1] is a run of identical characters
        identicalCharsPalindrome(s, i, r);

        i := r;

        // Expand around center
        while l > 0 && r < n - 1 && s[l - 1] == s[r + 1]
          invariant 0 <= l <= i
          invariant i <= r < n
          invariant IsPalindrome(s[l..r+1])
        {
            expandPalindrome(s, l, r);
            l := l - 1;
            r := r + 1;
        }

        var length := r - l + 1;
        if length > maxLength
        {
            start := l;
            maxLength := length;
        }

        substringWitness(s, start, maxLength);

        i := i + 1;
    }

    result := s[start..start + maxLength];
}

