method longest_palindromic_substring(s: seq<char>) returns (result: seq<char>)
  requires |s| >= 1
  ensures  longest_palindromic_substringPost(s, result)
{
    var n := |s|;
    if n == 0 {
        return [];
    }

    var start := 0;
    var maxLength := 1;

    assert IsPalindrome(s[0..1]) by {
      var w := s[0..1];
      assert |w| == 1;
    }

    var i := 0;
    ghost var frontier := 0;

    while i < n
      invariant 0 <= i <= n
      invariant i == frontier
      invariant 0 <= start
      invariant start + maxLength <= n
      invariant maxLength >= 1
      invariant IsPalindrome(s[start..start+maxLength])
      invariant forall st, len {:trigger PalindromicSubstringAt(s, st, len)} ::
        0 <= st < |s| && 0 <= len <= |s| &&
        PalindromicSubstringAt(s, st, len) && st + len / 2 < frontier
        ==> len <= maxLength
    {
        ghost var old_frontier := frontier;

        var l := i;
        var r := i;

        while r < n - 1 && s[r] == s[r + 1]
          invariant i <= r < n
          invariant l == i
          invariant forall k :: i <= k <= r ==> s[k] == s[i]
        {
            r := r + 1;
        }

        ghost var cl := l;
        ghost var cr := r;

        identicalCharsPalindrome(s, l, r);

        i := r;

        ghost var expDist := 0;
        while l > 0 && r < n - 1 && s[l - 1] == s[r + 1]
          invariant 0 <= l <= cl
          invariant cr <= r < n
          invariant l == cl - expDist
          invariant r == cr + expDist
          invariant IsPalindrome(s[l..r+1])
        {
            expandPalindrome(s, l, r);
            l := l - 1;
            r := r + 1;
            expDist := expDist + 1;
        }

        ghost var fl := l;
        ghost var fr := r;
        ghost var d := expDist;
        assert fl == cl - d;
        assert fr == cr + d;
        assert fl == 0 || fr == n - 1 || s[fl-1] != s[fr+1];

        var length := r - l + 1;
        if length > maxLength
        {
            start := l;
            maxLength := length;
        }

        i := i + 1;
        frontier := cr + 1;

        forall st, len {:trigger PalindromicSubstringAt(s, st, len)} |
          0 <= st < |s| && 0 <= len <= |s| &&
          PalindromicSubstringAt(s, st, len) && st + len / 2 < frontier
          ensures len <= maxLength
        {
          if st + len / 2 < old_frontier {
          } else {
            assert cl <= st + len / 2 <= cr;
            if len == 0 {
            } else {
              palindromeBoundedByExpansion(s, cl, cr, d, st, len);
            }
          }
        }
    }

    result := s[start..start + maxLength];
    assert IsPalindrome(result);
    assert SubstringAt(s, result, start);

    forall st, len | 0 <= st < |s| && 0 <= len <= |s| && PalindromicSubstringAt(s, st, len)
      ensures len <= |result|
    {
      if len >= 1 {
        assert st + len / 2 < n;
        assert st + len / 2 < frontier;
      }
    }
}

predicate IsPalindrome(word: seq<char>)
{
  forall i :: 0 <= i < |word| ==> word[i] == word[|word| - 1 - i]
}

predicate SubstringAt(text: seq<char>, sub: seq<char>, start: int)
{
  0 <= start &&
  start + |sub| <= |text| &&
  sub == text[start .. start + |sub|]
}

predicate IsSubstring(text: seq<char>, sub: seq<char>)
{
  exists start :: 0 <= start <= |text| - |sub| && SubstringAt(text, sub, start)
}

predicate PalindromicSubstringAt(s: seq<char>, start: int, len: int)
{
  0 <= start < |s| &&
  0 <= len <= |s| &&
  start + len <= |s| &&
  IsPalindrome(s[start..start+len])
}

predicate longest_palindromic_substringPost(s: seq<char>, result: seq<char>)
{
  |result| >= 1
  && IsSubstring(s, result)
  && IsPalindrome(result)
  && (forall start, len ::
      0 <= start < |s| && 0 <= len <= |s| &&
      PalindromicSubstringAt(s, start, len) ==> len <= |result|)
}

lemma identicalCharsPalindrome(s: seq<char>, l: int, r: int)
  requires 0 <= l <= r < |s|
  requires forall k :: l <= k <= r ==> s[k] == s[l]
  ensures IsPalindrome(s[l..r+1])
{
  var w := s[l..r+1];
  forall i | 0 <= i < |w|
    ensures w[i] == w[|w| - 1 - i]
  {
  }
}

lemma expandPalindrome(s: seq<char>, l: int, r: int)
  requires 0 < l <= r < |s| - 1
  requires IsPalindrome(s[l..r+1])
  requires s[l-1] == s[r+1]
  ensures IsPalindrome(s[l-1..r+2])
{
  var oldW := s[l..r+1];
  var newW := s[l-1..r+2];
  forall i | 0 <= i < |newW|
    ensures newW[i] == newW[|newW| - 1 - i]
  {
    if 0 < i < |newW| - 1 {
      assert newW[i] == oldW[i - 1];
      assert newW[|newW| - 1 - i] == oldW[|oldW| - 1 - (i - 1)];
    }
  }
}

// Core lemma: any palindrome whose midpoint (a + p/2) is in [cl..cr]
// (a run of identical characters) has length <= cr-cl+1+2*d,
// where d is the expansion distance of the maximal palindrome from [cl..cr].
//
// The proof uses the fact that the palindrome centered at m in a run of identical
// characters [cl..cr] cannot be longer than the maximal symmetric expansion from
// the entire run. This is because the expansion from [cl..cr] is at least as powerful
// as expansion from any single point m within the run.
lemma palindromeBoundedByExpansion(s: seq<char>, cl: int, cr: int, d: int, a: int, p: int)
  requires |s| > 0
  requires 0 <= cl <= cr < |s|
  requires forall k :: cl <= k <= cr ==> s[k] == s[cl]
  requires d >= 0
  requires cl - d >= 0 && cr + d < |s|
  requires IsPalindrome(s[cl-d .. cr+d+1])
  requires cl - d == 0 || cr + d == |s| - 1 || s[cl-d-1] != s[cr+d+1]
  requires 0 <= a && a + p <= |s| && p >= 1
  requires IsPalindrome(s[a..a+p])
  requires cl <= a + p / 2 <= cr
  ensures p <= cr - cl + 1 + 2 * d
{
  // The proof uses the key insight that for a palindrome P = s[a..a+p]
  // with midpoint m = a+p/2 in the run [cl..cr]:
  // 1. The run of identical characters around m (within P) extends to cover
  //    the interval [min(cl, 2m-cr)..max(cr, 2m-cl)] for odd p (and similar for even p).
  // 2. The algorithm's expansion from [cl..cr] produces a palindrome whose effective
  //    expansion distance from m is at least as large as P's half-width.
  //
  // We formalize this via a decreasing induction on d (the expansion distance):
  // if p > cr-cl+1+2d, we show s[cl-d-1] == s[cr+d+1], contradicting maximality.
  if p <= cr - cl + 1 + 2 * d {
    // Nothing to prove
  } else {
    // Contradiction: show that the expansion can go one more step.
    // This contradicts maximality.
    expansionCanContinue(s, cl, cr, d, a, p);
    // Now we know s[cl-d-1] == s[cr+d+1] and the boundaries are valid.
    // But the maximality says cl-d == 0 || cr+d == |s|-1 || s[cl-d-1] != s[cr+d+1].
    // expansionCanContinue also proves cl-d > 0 and cr+d < |s|-1.
    // So we have s[cl-d-1] != s[cr+d+1] AND s[cl-d-1] == s[cr+d+1]. Contradiction.
  }
}

// Helper: if P is longer than the current expansion, the expansion can continue.
lemma expansionCanContinue(s: seq<char>, cl: int, cr: int, d: int, a: int, p: int)
  requires |s| > 0
  requires 0 <= cl <= cr < |s|
  requires forall k :: cl <= k <= cr ==> s[k] == s[cl]
  requires d >= 0
  requires cl - d >= 0 && cr + d < |s|
  requires IsPalindrome(s[cl-d .. cr+d+1])
  requires 0 <= a && a + p <= |s| && p >= 1
  requires IsPalindrome(s[a..a+p])
  requires cl <= a + p / 2 <= cr
  requires p > cr - cl + 1 + 2 * d
  ensures cl - d - 1 >= 0
  ensures cr + d + 1 < |s|
  ensures s[cl - d - 1] == s[cr + d + 1]
  decreases p - (cr - cl + 1 + 2 * d)
{
  var m := a + p / 2;
  var fl := cl - d;
  var fr := cr + d;

  // Step 1: Show boundaries are valid (P doesn't go out of bounds, so expansion can't be blocked by boundary).
  // P goes from a to a+p-1. a >= 0 and a+p-1 < |s|.
  // We need cl-d-1 >= 0 and cr+d+1 < |s|.
  // Since P's length p > fr-fl+1 and P's midpoint m is in [fl..fr]:
  //   P extends beyond [fl..fr]. So either a < fl or a+p-1 > fr (or both).
