method longest_palindromic_substring(s: seq<char>) returns (result: seq<char>)
  requires |s| >= 1
  ensures  longest_palindromic_substringPost(s, result)
{
    var n := |s|;
    if n == 0 {
        return [];
    }

    var start := 0;
    var maxLength := 1;

    assert IsPalindrome(s[0..1]) by {
      var w := s[0..1];
      assert |w| == 1;
    }

    var i := 0;
    ghost var frontier := 0;

    while i < n
      invariant 0 <= i <= n
      invariant i == frontier
      invariant 0 <= start
      invariant start + maxLength <= n
      invariant maxLength >= 1
      invariant IsPalindrome(s[start..start+maxLength])
      invariant forall st, len {:trigger PalindromicSubstringAt(s, st, len)} ::
        0 <= st < |s| && 0 <= len <= |s| &&
        PalindromicSubstringAt(s, st, len) && st + len / 2 < frontier
        ==> len <= maxLength
    {
        ghost var old_frontier := frontier;

        var l := i;
        var r := i;

        while r < n - 1 && s[r] == s[r + 1]
          invariant i <= r < n
          invariant l == i
          invariant forall k :: i <= k <= r ==> s[k] == s[i]
        {
            r := r + 1;
        }

        ghost var cl := l;
        ghost var cr := r;

        identicalCharsPalindrome(s, l, r);

        i := r;

        ghost var expDist := 0;
        while l > 0 && r < n - 1 && s[l - 1] == s[r + 1]
          invariant 0 <= l <= cl
          invariant cr <= r < n
          invariant l == cl - expDist
          invariant r == cr + expDist
          invariant IsPalindrome(s[l..r+1])
        {
            expandPalindrome(s, l, r);
            l := l - 1;
            r := r + 1;
            expDist := expDist + 1;
        }

        ghost var fl := l;
        ghost var fr := r;
        ghost var d := expDist;
        assert fl == cl - d;
        assert fr == cr + d;
        assert fl == 0 || fr == n - 1 || s[fl-1] != s[fr+1];

        var length := r - l + 1;
        if length > maxLength
        {
            start := l;
            maxLength := length;
        }

        i := i + 1;
        frontier := cr + 1;

        forall st, len {:trigger PalindromicSubstringAt(s, st, len)} |
          0 <= st < |s| && 0 <= len <= |s| &&
          PalindromicSubstringAt(s, st, len) && st + len / 2 < frontier
          ensures len <= maxLength
        {
          if st + len / 2 < old_frontier {
          } else {
            assert cl <= st + len / 2 <= cr;
            if len == 0 {
            } else {
              palindromeBoundedByExpansion(s, cl, cr, d, st, len);
            }
          }
        }
    }

    result := s[start..start + maxLength];
    assert IsPalindrome(result);
    assert SubstringAt(s, result, start);

    forall st, len | 0 <= st < |s| && 0 <= len <= |s| && PalindromicSubstringAt(s, st, len)
      ensures len <= |result|
    {
      if len >= 1 {
        assert st + len / 2 < n;
        assert st + len / 2 < frontier;
      }
    }
}

predicate IsPalindrome(word: seq<char>)
{
  forall i :: 0 <= i < |word| ==> word[i] == word[|word| - 1 - i]
}

predicate SubstringAt(text: seq<char>, sub: seq<char>, start: int)
{
  0 <= start &&
  start + |sub| <= |text| &&
  sub == text[start .. start + |sub|]
}

predicate IsSubstring(text: seq<char>, sub: seq<char>)
{
  exists start :: 0 <= start <= |text| - |sub| && SubstringAt(text, sub, start)
}

predicate PalindromicSubstringAt(s: seq<char>, start: int, len: int)
{
  0 <= start < |s| &&
  0 <= len <= |s| &&
  start + len <= |s| &&
  IsPalindrome(s[start..start+len])
}

predicate longest_palindromic_substringPost(s: seq<char>, result: seq<char>)
{
  |result| >= 1
  && IsSubstring(s, result)
  && IsPalindrome(result)
  && (forall start, len ::
      0 <= start < |s| && 0 <= len <= |s| &&
      PalindromicSubstringAt(s, start, len) ==> len <= |result|)
}

lemma identicalCharsPalindrome(s: seq<char>, l: int, r: int)
  requires 0 <= l <= r < |s|
  requires forall k :: l <= k <= r ==> s[k] == s[l]
  ensures IsPalindrome(s[l..r+1])
{
  var w := s[l..r+1];
  forall i | 0 <= i < |w|
    ensures w[i] == w[|w| - 1 - i]
  {
  }
}

lemma expandPalindrome(s: seq<char>, l: int, r: int)
  requires 0 < l <= r < |s| - 1
  requires IsPalindrome(s[l..r+1])
  requires s[l-1] == s[r+1]
  ensures IsPalindrome(s[l-1..r+2])
{
  var oldW := s[l..r+1];
  var newW := s[l-1..r+2];
  forall i | 0 <= i < |newW|
    ensures newW[i] == newW[|newW| - 1 - i]
  {
    if 0 < i < |newW| - 1 {
      assert newW[i] == oldW[i - 1];
      assert newW[|newW| - 1 - i] == oldW[|oldW| - 1 - (i - 1)];
    }
  }
}

// Helper: access palindrome character matching
lemma palAt(s: seq<char>, a: int, p: int, j: int)
  requires 0 <= a && a + p <= |s| && p >= 1
  requires IsPalindrome(s[a..a+p])
  requires 0 <= j < p
  ensures s[a + j] == s[a + p - 1 - j]
{
  var w := s[a..a+p];
  assert w[j] == w[p - 1 - j];
}

// Key lemma: any palindrome P with midpoint in [cl..cr] (a run of identical chars)
// is bounded by the maximal symmetric expansion from [cl..cr].
// Additional fact: the run ends at cr (cr == |s|-1 or s[cr+1] != s[cl]).
lemma palindromeBoundedByExpansion(s: seq<char>, cl: int, cr: int, d: int, a: int, p: int)
  requires |s| > 0
  requires 0 <= cl <= cr < |s|
  requires forall k :: cl <= k <= cr ==> s[k] == s[cl]
  requires cr == |s| - 1 || s[cr + 1] != s[cl]  // run ends at cr
  requires d >= 0
  requires cl - d >= 0 && cr + d < |s|
  requires IsPalindrome(s[cl-d .. cr+d+1])
  requires cl - d == 0 || cr + d == |s| - 1 || s[cl-d-1] != s[cr+d+1]
  requires 0 <= a && a + p <= |s| && p >= 1
  requires IsPalindrome(s[a..a+p])
  requires cl <= a + p / 2 <= cr
  ensures p <= cr - cl + 1 + 2 * d
{
  if p <= cr - cl + 1 + 2 * d {
  } else {
    var m := a + p / 2;
    var fl := cl - d;
    var fr := cr + d;

    // P is longer than Q. Show both boundaries are not blocking.
    if a >= fl && a + p - 1 <= fr {
      // P contained in Q: p <= fr - fl + 1 = cr-cl+1+2d. Contradiction.
      assert false;
    }

    // P extends beyond Q on at least one side.
    // Show it extends on both sides (or derive contradiction if it extends on only one side).

    // First, handle the case where P extends only right (a >= fl, a+p-1 > fr):
    if a >= fl && a + p - 1 > fr {
      // P doesn't extend left but extends right.
      // Show this leads to contradiction using the run-end condition.
      pExtendsOnlyRight(s, cl, cr, d, a, p);
      assert false;
    }

    // Symmetric case: P extends only left.
    if a < fl && a + p - 1 <= fr {
      pExtendsOnlyLeft(s, cl, cr, d, a, p);
      assert false;
    }

    // P extends beyond Q on BOTH sides: a < fl and a+p-1 > fr.
    assert a < fl && a + p - 1 > fr;
    assert a < cl - d;  // so cl - d > 0, i.e., cl - d - 1 >= 0
    assert a + p - 1 > cr + d;  // so cr + d + 1 <= a + p - 1 < |s|, i.e., cr + d + 1 < |s|

    // Now show s[fl-1] == s[fr+1], contradicting maximality.
    pExtendsBothSides(s, cl, cr, d, a, p);
  }
}

// Sub-lemma: P can't extend only to the right of Q.
lemma pExtendsOnlyRight(s: seq<char>, cl: int, cr: int, d: int, a: int, p: int)
  requires |s| > 0
  requires 0 <= cl <= cr < |s|
  requires forall k :: cl <= k <= cr ==> s[k] == s[cl]
  requires cr == |s| - 1 || s[cr + 1] != s[cl]
  requires d >= 0
  requires cl - d >= 0 && cr + d < |s|
  requires IsPalindrome(s[cl-d .. cr+d+1])
  requires 0 <= a && a + p <= |s| && p >= 1
  requires IsPalindrome(s[a..a+p])
  requires cl <= a + p / 2 <= cr
  requires p > cr - cl + 1 + 2 * d
  requires a >= cl - d    // P doesn't extend left of Q
  requires a + p - 1 > cr + d  // P extends right of Q
  ensures false
{
  var m := a + p / 2;
  var fl := cl - d;
  var fr := cr + d;
  var c := s[cl];

  // P extends right of Q: position cr+d+1 is in P.
  // From P palindrome: s[cr+d+1] == s[a+p-1-(cr+d+1-a)] = s[2a+p-2-cr-d].
  // Let R = 2a+p-2-cr-d.
  var R := 2*a + p - 2 - cr - d;

  // Show R is in [cl..cr] (in the run).
  // R = 2*a+p-2-cr-d. a = m - p/2. 2*a+p = 2m + (p % 2).
  // R = 2m + (p%2) - 2 - cr - d.
  // R >= cl: 2m+(p%2)-2-cr-d >= cl iff 2m+(p%2) >= cl+cr+d+2.
  //   m >= p/2 (since a = m-p/2 >= 0). And p > cr-cl+1+2d.
  //   So m >= p/2 > (cr-cl+1+2d)/2 = (cr-cl+2d)/2+1/2.
  //   Integer: m >= (cr-cl+2d)/2 + 1 = (cr-cl+2d+2)/2.
  //   2m >= cr-cl+2d+2.
  //   2m+(p%2) >= cr-cl+2d+2. We need >= cl+cr+d+2.
  //   cr-cl+2d+2 >= cl+cr+d+2 iff d >= 2cl. Hmm, not always true.
  //
  // This approach isn't working directly. Let me try differently.

  // Since cr < |s|-1 || cr == |s|-1:
  // Case cr == |s|-1: fr = cr+d = |s|-1+d. But fr < |s| means d = 0 and fr = |s|-1.
  //   p > cr-cl+1. a+p-1 > |s|-1 means a+p > |s|. But a+p <= |s|. Contradiction!
  if cr == |s| - 1 {
    assert d == 0;
    assert fr == |s| - 1;
    assert a + p - 1 > fr == |s| - 1;
    assert a + p > |s|;
    assert false;
  }

  // So cr < |s| - 1, and s[cr+1] != c.
  assert cr < |s| - 1;
  assert s[cr + 1] != c;

  // From P palindrome, position cr+1 is in P (since a+p-1 > cr+d >= cr+1 when d >= 1, or a+p-1 > cr+d >= cr when d >= 0).
  // Wait, a+p-1 > cr+d and cr+d >= cr, so a+p-1 > cr, meaning a+p-1 >= cr+1.
  // So cr+1 is in P if cr+1 <= a+p-1, which is true.
  assert cr + 1 <= a + p - 1;

  // From P palindrome: s[cr+1] == s[a+p-1-(cr+1-a)] = s[2a+p-cr-2].
  palAt(s, a, p, cr + 1 - a);
  var R2 := 2*a + p - cr - 2;
  assert s[cr + 1] == s[R2];

  // Show R2 is in [cl..cr].
  // R2 = 2a+p-cr-2.
  // R2 >= a (since a+p-cr-2 >= 0 iff a+p >= cr+2, which follows from a+p-1 >= cr+1).
  assert R2 >= a;
  // R2 >= cl? R2 = 2a+p-cr-2. a >= cl-d. R2 >= 2(cl-d)+p-cr-2 = 2cl-2d+p-cr-2.
  //   p > cr-cl+1+2d. R2 > 2cl-2d+(cr-cl+1+2d)-cr-2 = 2cl-2d+cr-cl+1+2d-cr-2 = cl-1.
  //   So R2 >= cl.
  assert R2 >= cl;

  // R2 <= cr? R2 = 2a+p-cr-2. Since m <= cr: 2m <= 2cr. 2a+p = 2m+(p%2).
  //   R2 = 2m+(p%2)-cr-2 <= 2cr+1-cr-2 = cr-1 <= cr.
  assert R2 <= cr;

  // So R2 is in [cl..cr], meaning s[R2] == c.
  assert cl <= R2 <= cr;
  assert s[R2] == c;

  // But s[cr+1] == s[R2] == c, contradicting s[cr+1] != c.
  assert s[cr + 1] == c;
  assert false;
}

// Sub-lemma: P can't extend only to the left of Q.
lemma pExtendsOnlyLeft(s: seq<char>, cl: int, cr: int, d: int, a: int, p: int)
  requires |s| > 0
  requires 0 <= cl <= cr < |s|
  requires forall k :: cl <= k <= cr ==> s[k] == s[cl]
  requires cr == |s| - 1 || s[cr + 1] != s[cl]
  requires d >= 0
  requires cl - d >= 0 && cr + d < |s|
  requires IsPalindrome(s[cl-d .. cr+d+1])
  requires 0 <= a && a + p <= |s| && p >= 1
  requires IsPalindrome(s[a..a+p])
  requires cl <= a + p / 2 <= cr
  requires p > cr - cl + 1 + 2 * d
  requires a < cl - d        // P extends left of Q
  requires a + p - 1 <= cr + d  // P doesn't extend right of Q
  ensures false
{
  var m := a + p / 2;
  var fl := cl - d;
  var fr := cr + d;
  var c := s[cl];

  // P extends left: position fl-1 = cl-d-1 is in P (a < fl means a <= fl-1).
  assert a <= fl - 1;
  // Also fl - 1 >= 0 since a >= 0 and a <= fl-1.
  assert fl - 1 >= 0;

  // From P palindrome at position fl-1: s[fl-1] == s[a+p-1-(fl-1-a)] = s[2a+p-fl].
  palAt(s, a, p, fl - 1 - a);
  var R := 2*a + p - fl;
  assert s[fl - 1] == s[R];

  // Show R is in [cl..cr].
  // R = 2a+p-fl = 2a+p-cl+d. Since m <= cr: 2a+p = 2m+(p%2) <= 2cr+(p%2).
  //   R <= 2cr+(p%2)-cl+d.
  // R >= cl? R = 2a+p-cl+d. 2a+p = 2m+(p%2). R = 2m+(p%2)-cl+d >= 2cl+0-cl+0 = cl (since m >= cl, d >= 0).
  assert R >= cl;

  // R <= cr? R = 2m+(p%2)-cl+d.
  //   a+p-1 <= fr = cr+d, so a+p <= cr+d+1, so 2a+p <= a+cr+d+1.
  //   R = 2a+p-cl+d <= a+cr+d+1-cl+d = a+cr-cl+2d+1.
  //   Since a < fl = cl-d: a <= cl-d-1. R <= cl-d-1+cr-cl+2d+1 = cr+d.
  //   And R <= cr? R <= cr+d doesn't directly give R <= cr.
  //   Hmm. Let me try: R = 2m+(p%2)-cl+d. Since m <= cr: R <= 2cr+1-cl+d.
  //   We need R <= cr: 2cr+1-cl+d <= cr iff cr+1+d <= cl iff cr < cl-d = fl-1... impossible since cl <= cr.
  //   So R > cr in general!

  // R might be outside the run on the right side. R is in [cl..fr] (in Q)?
  // R <= fr = cr+d? R = 2m+(p%2)-cl+d. Since m <= cr: R <= 2cr+1-cl+d = cr+d+(cr+1-cl) >= cr+d+1 > cr+d = fr.
  // Wait: cr+1-cl >= 1 (since cr >= cl). So R >= cr+d+1 > fr. R > fr!

  // R might be OUTSIDE Q too. But R <= a+p-1 (since R is the mirror of fl-1 in P, and fl-1 >= a,
  // so mirror <= a+p-1). And a+p-1 <= fr. So R <= fr.
  // Wait: R = 2a+p-(fl-1)-1 = 2a+p-fl. And fl-1 >= a means R = 2a+p-fl <= 2a+p-a-1 = a+p-1 <= fr.
  // OK so R <= fr. Good.

  // So R in [cl..fr]. Is R in [cl..cr]?
  // R = 2m+(p%2)-cl+d.
  // If d = 0: R = 2m+(p%2)-cl. Since m >= cl: R >= cl+(p%2) >= cl.
  //   R <= cr iff 2m+(p%2) <= cl+cr. Since m <= cr: 2m <= 2cr. cl+cr >= cl+cl = 2cl.
  //   Not guaranteed.

  // If R is NOT in [cl..cr], it's in [cr+1..fr]. Then use Q palindrome.
  // From Q palindrome: s[R] == s[fl+fr-R] = s[cl-d+cr+d-R] = s[cl+cr-R].
  // cl+cr-R = cl+cr-(2m+(p%2)-cl+d) = 2cl+cr-2m-(p%2)-d.

  // Is cl+cr-R in [cl..cr]? cl+cr-R = 2cl+cr-2m-(p%2)-d.
  // >= cl iff cl+cr-2m-(p%2)-d >= 0 iff cl+cr >= 2m+(p%2)+d.
  //   Since R >= cl: 2m+(p%2)-cl+d >= cl, so 2m+(p%2)+d >= 2cl, cl+cr >= 2cl (cr >= cl). Hmm.
  //   cl+cr >= 2m+(p%2)+d doesn't follow.
  // <= cr iff 2cl+cr-2m-(p%2)-d <= cr iff 2cl-2m-(p%2)-d <= 0 iff 2m+(p%2)+d >= 2cl.
  //   Since m >= cl: 2m >= 2cl and (p%2)+d >= 0. So yes.

  // So cl+cr-R <= cr. But >= cl? Not guaranteed.
  // If cl+cr-R < cl, i.e., it's in [fl..cl-1], we can continue the chain.
  // This ping-pong might not terminate.

  // Let me try a different approach for this case.
  // P extends left but not right. P has length p, with left end at a < fl.
  // Right end at a+p-1 <= fr.
