  // If R < fl: R is in P but not in Q. It's to the left of Q.
  //   From P palindrome, s[fr+1] = s[R]. And from Q palindrome if R were in Q, we could relate.
  //   But R is outside Q. We need another approach.

  // Let me try the mirror of fl-1 through P instead.
  var j_l := fl - 1 - a;
  assert 0 <= j_l < p;
  palAt(s, a, p, j_l);
  var L := 2*a + p - fl;  // = a + p - 1 - j_l
  assert L == a + p - 1 - j_l;
  assert s[fl - 1] == s[L];

