  1→predicate IsPalindrome(word: seq<char>)
  2→{
  3→  forall i :: 0 <= i < |word| ==> word[i] == word[|word| - 1 - i]
  4→}
  5→
  6→predicate SubstringAt(text: seq<char>, sub: seq<char>, start: int)
  7→{
  8→  0 <= start &&
  9→  start + |sub| <= |text| &&
 10→  sub == text[start .. start + |sub|]
 11→}
 12→
 13→predicate IsSubstring(text: seq<char>, sub: seq<char>)
 14→{
 15→  exists start :: 0 <= start <= |text| - |sub| && SubstringAt(text, sub, start)
 16→}
 17→
 18→predicate PalindromicSubstringAt(s: seq<char>, start: int, len: int)
 19→{
 20→  0 <= start < |s| &&
 21→  0 <= len <= |s| &&
 22→  start + len <= |s| &&
 23→  IsPalindrome(s[start..start+len])
 24→}
 25→
 26→predicate longest_palindromic_substringPost(s: seq<char>, result: seq<char>)
 27→{
 28→  |result| >= 1
 29→  && IsSubstring(s, result)
 30→  && IsPalindrome(result)
 31→  && (forall start, len ::
 32→      0 <= start < |s| && 0 <= len <= |s| &&
 33→      PalindromicSubstringAt(s, start, len) ==> len <= |result|)
 34→}
 35→
 36→lemma identicalCharsPalindrome(s: seq<char>, l: int, r: int)
 37→  requires 0 <= l <= r < |s|
 38→  requires forall k :: l <= k <= r ==> s[k] == s[l]
 39→  ensures IsPalindrome(s[l..r+1])
 40→{
 41→  var w := s[l..r+1];
 42→  forall i | 0 <= i < |w|
 43→    ensures w[i] == w[|w| - 1 - i]
 44→  {
 45→  }
 46→}
 47→
 48→lemma expandPalindrome(s: seq<char>, l: int, r: int)
 49→  requires 0 < l <= r < |s| - 1
 50→  requires IsPalindrome(s[l..r+1])
 51→  requires s[l-1] == s[r+1]
 52→  ensures IsPalindrome(s[l-1..r+2])
 53→{
 54→  var oldW := s[l..r+1];
 55→  var newW := s[l-1..r+2];
 56→  forall i | 0 <= i < |newW|
 57→    ensures newW[i] == newW[|newW| - 1 - i]
 58→  {
 59→    if 0 < i < |newW| - 1 {
 60→      assert newW[i] == oldW[i - 1];
 61→      assert newW[|newW| - 1 - i] == oldW[|oldW| - 1 - (i - 1)];
 62→    }
 63→  }
 64→}
 65→
 66→lemma palAt(s: seq<char>, a: int, p: int, j: int)
 67→  requires 0 <= a && a + p <= |s| && p >= 1
 68→  requires IsPalindrome(s[a..a+p])
 69→  requires 0 <= j < p
 70→  ensures s[a + j] == s[a + p - 1 - j]
 71→{
 72→  var w := s[a..a+p];
 73→  assert w[j] == w[p - 1 - j];
 74→}
 75→
 76→// Main optimality lemma. Requires:
 77→// - [cl..cr] is a run of identical characters, maximal on both sides
 78→// - s[cl-d..cr+d+1] is the maximal palindrome from symmetric expansion of the run
 79→// - P = s[a..a+p] is a palindrome with midpoint in [cl..cr]
 80→lemma palindromeBoundedByExpansion(s: seq<char>, cl: int, cr: int, d: int, a: int, p: int)
 81→  requires |s| > 0
 82→  requires 0 <= cl <= cr < |s|
 83→  requires forall k :: cl <= k <= cr ==> s[k] == s[cl]
 84→  requires cl == 0 || s[cl - 1] != s[cl]  // run doesn't extend left
 85→  requires cr == |s| - 1 || s[cr + 1] != s[cl]  // run doesn't extend right
 86→  requires d >= 0
 87→  requires cl - d >= 0 && cr + d < |s|
 88→  requires IsPalindrome(s[cl-d .. cr+d+1])
 89→  requires cl - d == 0 || cr + d == |s| - 1 || s[cl-d-1] != s[cr+d+1]
 90→  requires 0 <= a && a + p <= |s| && p >= 1
 91→  requires IsPalindrome(s[a..a+p])
 92→  requires cl <= a + p / 2 <= cr
 93→  ensures p <= cr - cl + 1 + 2 * d
 94→{
 95→  if p <= cr - cl + 1 + 2 * d {
 96→  } else {
 97→    var fl := cl - d;
 98→    var fr := cr + d;
 99→    // P is strictly longer than Q.
100→    if a >= fl && a + p - 1 <= fr {
101→      assert p <= fr - fl + 1;
102→      assert false;
103→    }
104→    if a >= fl && a + p - 1 > fr {
105→      pExtendsOnlyRight(s, cl, cr, d, a, p);
106→    }
107→    if a < fl && a + p - 1 <= fr {
108→      pExtendsOnlyLeft(s, cl, cr, d, a, p);
109→    }
110→    if a < fl && a + p - 1 > fr {
111→      pExtendsBothSides(s, cl, cr, d, a, p);
112→    }
113→  }
114→}
115→
116→// P extends only right of Q: mirror of cr+1 lands in the run, giving s[cr+1] = c. Contradiction.
117→lemma pExtendsOnlyRight(s: seq<char>, cl: int, cr: int, d: int, a: int, p: int)
118→  requires |s| > 0
119→  requires 0 <= cl <= cr < |s|
120→  requires forall k :: cl <= k <= cr ==> s[k] == s[cl]
121→  requires cr == |s| - 1 || s[cr + 1] != s[cl]
122→  requires d >= 0 && cl - d >= 0 && cr + d < |s|
123→  requires 0 <= a && a + p <= |s| && p >= 1
124→  requires IsPalindrome(s[a..a+p])
125→  requires cl <= a + p / 2 <= cr
126→  requires p > cr - cl + 1 + 2 * d
127→  requires a >= cl - d && a + p - 1 > cr + d
128→  ensures false
129→{
130→  var c := s[cl];
131→  // cr < |s|-1 (since a+p-1 > cr+d, a+p <= |s|)
132→  if cr == |s| - 1 {
133→    assert d == 0;
134→    assert a + p > |s|;
135→    assert false;
136→  }
137→  assert s[cr + 1] != c;
138→
139→  // Mirror of cr+1 in P
140→  palAt(s, a, p, cr + 1 - a);
141→  var R := 2 * a + p - 2 - cr;
142→  assert s[cr + 1] == s[R];
143→
144→  // R in [cl..cr]: R >= cl (from a >= cl-d and p > cr-cl+1+2d: 2a+p > 2(cl-d)+cr-cl+1+2d = cl+cr+1, so R = 2a+p-2-cr >= cl)
145→  assert 2 * a + p > cl + cr + 1;
146→  assert R >= cl;
147→  // R <= cr (from m <= cr)
148→  assert R <= cr;
149→  assert s[R] == c;
150→  assert false;
151→}
152→
153→// P extends only left of Q: mirror of cl-1 lands in the run, giving s[cl-1] = c. Contradiction.
154→lemma pExtendsOnlyLeft(s: seq<char>, cl: int, cr: int, d: int, a: int, p: int)
155→  requires |s| > 0
156→  requires 0 <= cl <= cr < |s|
157→  requires forall k :: cl <= k <= cr ==> s[k] == s[cl]
158→  requires cl == 0 || s[cl - 1] != s[cl]
159→  requires d >= 0 && cl - d >= 0 && cr + d < |s|
160→  requires 0 <= a && a + p <= |s| && p >= 1
161→  requires IsPalindrome(s[a..a+p])
162→  requires cl <= a + p / 2 <= cr
163→  requires p > cr - cl + 1 + 2 * d
164→  requires a < cl - d && a + p - 1 <= cr + d
165→  ensures false
166→{
167→  var c := s[cl];
168→  // cl > 0 (since a < cl-d, a >= 0, so cl-d > 0, cl >= d+1 >= 1)
169→  assert cl > 0;
170→  assert s[cl - 1] != c;
171→
172→  // Mirror of cl-1 in P (cl-1 is in P since a <= cl-d-1 <= cl-1)
173→  palAt(s, a, p, cl - 1 - a);
174→  var L := 2 * a + p - cl;
175→  assert s[cl - 1] == s[L];
176→
177→  // L in [cl..cr]:
178→  // L >= cl: 2a+p >= 2cl. Since m = a+p/2 >= cl: 2m >= 2cl, 2a+p = 2m+(p%2) >= 2cl. So L >= cl.
179→  assert L >= cl;
180→  // L <= cr: 2a+p <= cl+cr.
181→  //   a < cl-d means a <= cl-d-1. a+p-1 <= cr+d means a+p <= cr+d+1.
182→  //   2a+p = a + (a+p) <= (cl-d-1) + (cr+d+1) = cl+cr.
183→  assert 2 * a + p <= cl + cr;
184→  assert L <= cr;
185→
186→  assert s[L] == c;
187→  assert s[cl - 1] == c;
188→  assert false;
189→}
190→
191→// P extends both sides of Q: derive contradiction.
192→// Use combined palindrome reflections and run properties.
193→lemma pExtendsBothSides(s: seq<char>, cl: int, cr: int, d: int, a: int, p: int)
194→  requires |s| > 0
195→  requires 0 <= cl <= cr < |s|
196→  requires forall k :: cl <= k <= cr ==> s[k] == s[cl]
197→  requires cl == 0 || s[cl - 1] != s[cl]
198→  requires cr == |s| - 1 || s[cr + 1] != s[cl]
199→  requires d >= 0 && cl - d >= 0 && cr + d < |s|
200→  requires IsPalindrome(s[cl-d .. cr+d+1])
201→  requires cl - d == 0 || cr + d == |s| - 1 || s[cl-d-1] != s[cr+d+1]
202→  requires 0 <= a && a + p <= |s| && p >= 1
203→  requires IsPalindrome(s[a..a+p])
204→  requires cl <= a + p / 2 <= cr
205→  requires p > cr - cl + 1 + 2 * d
206→  requires a < cl - d && a + p - 1 > cr + d
207→  ensures false
208→{
209→  var fl := cl - d;
210→  var fr := cr + d;
211→  var c := s[cl];
212→  var m := a + p / 2;
213→
214→  // Boundaries: fl > 0 and fr < |s|-1
215→  assert fl > 0;   // a < fl and a >= 0
216→  assert fr < |s| - 1;  // a+p-1 > fr and a+p <= |s|
217→
218→  // cr < |s|-1 and cl > 0 (from boundaries since fl = cl-d >= 1 gives cl >= d+1 >= 1,
219→  // and fr = cr+d < |s|-1 gives cr < |s|-1)
220→  assert cl > 0;
221→  assert cr < |s| - 1;
222→  assert s[cl - 1] != c;
223→  assert s[cr + 1] != c;
224→
225→  // Use the palindrome P to show that characters near the run boundary must equal c.
226→  // Position cl in P: s[cl] = c.
227→  // Mirror of cl through P: s[cl] = s[a+p-1-(cl-a)] = s[2a+p-1-cl].
228→  palAt(s, a, p, cl - a);
229→  assert s[cl] == s[2*a + p - 1 - cl];
230→
231→  // Position cr in P: s[cr] = c.
232→  // Mirror of cr through P: s[cr] = s[a+p-1-(cr-a)] = s[2a+p-1-cr].
233→  palAt(s, a, p, cr - a);
234→  assert s[cr] == s[2*a + p - 1 - cr];
235→
236→  // Where are these mirrors?
237→  var Mcl := 2*a + p - 1 - cl;  // mirror of cl
238→  var Mcr := 2*a + p - 1 - cr;  // mirror of cr
239→
240→  // Mcr = 2a+p-1-cr. Since a+p-1 > cr+d: Mcr = 2a+p-1-cr > a+d >= d >= 0. And Mcr < a+p (since cr >= 0... actually Mcr = 2a+p-1-cr <= 2a+p-1).
241→  // More usefully: Mcr = (a+p-1) + (a-cr) = (a+p-1) - (cr-a). Since cr-a >= cr-cl+d+1 (from a < cl-d... a <= cl-d-1, cr-a >= cr-cl+d+1):
242→  //   Mcr = (a+p-1) - (cr-a). And (a+p-1) > cr+d. cr-a >= cr-cl+d+1.
243→  //   Mcr = (a+p-1)-(cr-a) > (cr+d)-(cr-cl+d+1-1) = cl. Hmm: > cr+d - cr + cl - d = cl. So Mcr > cl? Let me recheck.
244→  //   Actually, Mcr = a + (a+p-1-cr). a+p-1-cr > d (since a+p-1 > cr+d). So Mcr > a + d >= 0 + 0 = 0.
245→  //   Mcr >= cl? Mcr = 2a+p-1-cr. 2a+p = 2m+(p%2). Mcr = 2m+(p%2)-1-cr.
246→  //   Since m >= cl: Mcr >= 2cl+(p%2)-1-cr.
247→  //   If cl = cr (single char run): Mcr >= 2cl+(p%2)-1-cl = cl+(p%2)-1 >= cl-1. So Mcr >= cl iff p%2 >= 1, i.e., p odd.
248→  //   For p even and cl = cr: Mcr = cl-1. s[cl-1] = s[cr] = c. But s[cl-1] != c. Contradiction!
249→
250→  // Handle the case where Mcr >= cl and Mcr <= cr (mirror of cr is in the run):
251→  // Then s[Mcr] = c. And s[cr] = s[Mcr] = c. (Already known, not useful.)
252→  // Try mirror of cr+1 instead:
253→  palAt(s, a, p, cr + 1 - a);
254→  var Mcr1 := 2*a + p - 2 - cr;  // mirror of cr+1
255→  assert s[cr + 1] == s[Mcr1];
256→
257→  // Mcr1 = 2a+p-2-cr = Mcr - 1.
258→  // If Mcr >= cl: Mcr1 >= cl-1.
259→  // If Mcr1 >= cl: s[Mcr1] in run, = c. Then s[cr+1] = c. Contradiction!
260→  // If Mcr1 = cl-1: s[Mcr1] = s[cl-1]. And s[cr+1] = s[cl-1].
261→  //   s[cr+1] != c and s[cl-1] != c. So both are not c but might be equal.
262→
263→  // Similarly, mirror of cl-1:
264→  palAt(s, a, p, cl - 1 - a);
265→  var Mcl0 := 2*a + p - cl;  // mirror of cl-1
266→  assert s[cl - 1] == s[Mcl0];
267→
268→  // Mcl0 = 2a+p-cl = Mcl + 1.
269→  // If Mcl <= cr: Mcl0 <= cr+1.
270→  // If Mcl0 <= cr: s[Mcl0] in run, = c. Then s[cl-1] = c. Contradiction!
271→  // If Mcl0 = cr+1: s[Mcl0] = s[cr+1]. And s[cl-1] = s[cr+1].
272→  //   Same as above.
273→
274→  // Summary of cases:
275→  // Mcr1 = 2a+p-2-cr = 2m+(p%2)-2-cr.
276→  // Mcl0 = 2a+p-cl = 2m+(p%2)-cl.
277→  //
278→  // Case A: Mcr1 >= cl (i.e., 2m+(p%2) >= cl+cr+2): s[cr+1] = s[Mcr1] = c. Contradiction.
279→  // Case B: Mcl0 <= cr (i.e., 2m+(p%2) <= cl+cr): s[cl-1] = s[Mcl0] = c. Contradiction.
280→  // Case C: Mcr1 < cl AND Mcl0 > cr: 2m+(p%2) < cl+cr+2 AND 2m+(p%2) > cl+cr.
281→  //   So 2m+(p%2) == cl+cr+1 (the only integer value in the open interval (cl+cr, cl+cr+2)).
282→  //   Then Mcr1 = cl+cr+1-2-cr = cl-1. So s[cr+1] = s[cl-1].
283→  //   And Mcl0 = cl+cr+1-cl = cr+1. So s[cl-1] = s[cr+1].
284→  //   Both give s[cl-1] = s[cr+1].
285→  //
286→  //   Now use Q maximality: fl == 0 || fr == |s|-1 || s[fl-1] != s[fr+1].
287→  //   Since fl > 0 and fr < |s|-1: s[fl-1] != s[fr+1].
288→  //
289→  //   We need to relate s[fl-1] and s[fr+1] to s[cl-1] and s[cr+1].
290→  //   If d = 0: fl-1 = cl-1 and fr+1 = cr+1. So s[cl-1] != s[cr+1]. But we showed s[cl-1] = s[cr+1]. Contradiction!
291→  //   If d > 0: fl-1 = cl-d-1 and fr+1 = cr+d+1. Different from cl-1 and cr+1.
292→  //     We showed s[cl-1] = s[cr+1] (both not c, but equal).
293→  //     We need s[fl-1] = s[fr+1] to contradict maximality.
294→  //     From Q palindrome: s[fl+j] = s[fr-j] for j in [0..fr-fl].
295→  //     s[cl-1] in Q (cl-1 >= fl since cl >= fl+d... cl-1 = cl-1, fl = cl-d, cl-1 >= cl-d iff d >= 1). Yes for d >= 1.
296→  //     From Q: s[cl-1] = s[fl+fr-(cl-1)] = s[cl+cr-cl+1] = s[cr+1]. Consistent.
297→  //     s[fl-1] is NOT in Q (fl-1 < fl).
298→  //     s[fr+1] is NOT in Q (fr+1 > fr).
299→  //     Both are in P (a < fl-1 < ... wait, a < fl means a <= fl-1, so fl-1 >= a. Similarly fr+1 <= a+p-1.)
300→
301→  //     From P: s[fl-1] = s[2a+p-fl] and s[fr+1] = s[2a+p-2-fr].
302→  //     2a+p-fl = 2a+p-cl+d. 2a+p-2-fr = 2a+p-2-cr-d.
303→  //     In Case C: 2a+p = 2m+(p%2) = cl+cr+1.
304→  //     2a+p-fl = cl+cr+1-cl+d = cr+d+1 = fr+1.
305→  //     So s[fl-1] = s[fr+1]. This directly gives s[fl-1] = s[fr+1].
306→  //     From maximality: s[fl-1] != s[fr+1]. CONTRADICTION!
307→
308→  // So ALL cases (A, B, C) lead to contradiction.
309→
310→  if 2*a + p >= cl + cr + 2 {
311→    // Case A: Mcr1 >= cl
312→    assert Mcr1 >= cl;
313→    assert Mcr1 <= cr;  // Mcr1 = 2m+(p%2)-2-cr <= 2cr+1-2-cr = cr-1 <= cr
314→    assert s[Mcr1] == c;
315→    assert s[cr + 1] == c;
316→    assert false;
317→  } else if 2*a + p <= cl + cr {
318→    // Case B: Mcl0 <= cr
319→    assert Mcl0 <= cr;
320→    assert Mcl0 >= cl;  // 2m+(p%2)-cl >= 2cl-cl = cl
321→    assert s[Mcl0] == c;
322→    assert s[cl - 1] == c;
323→    assert false;
324→  } else {
325→    // Case C: 2a+p == cl+cr+1
326→    assert 2*a + p == cl + cr + 1;
327→    // s[fl-1]'s mirror in P is at 2a+p-fl = cl+cr+1-cl+d = cr+d+1 = fr+1.
328→    assert 2*a + p - fl == fr + 1;
329→    palAt(s, a, p, fl - 1 - a);
330→    assert s[fl - 1] == s[fr + 1];
331→    // Maximality: s[fl-1] != s[fr+1] since fl > 0 and fr < |s|-1.
332→    assert false;
333→  }
334→}
335→
336→method longest_palindromic_substring(s: seq<char>) returns (result: seq<char>)
337→  requires |s| >= 1
338→  ensures  longest_palindromic_substringPost(s, result)
339→{
340→    var n := |s|;
341→    if n == 0 {
342→        return [];
343→    }
344→
345→    var start := 0;
346→    var maxLength := 1;
347→
348→    assert IsPalindrome(s[0..1]) by {
349→      var w := s[0..1];
350→      assert |w| == 1;
351→    }
352→
353→    var i := 0;
354→    ghost var frontier := 0;
355→
356→    while i < n
357→      invariant 0 <= i <= n
358→      invariant i == frontier
359→      invariant 0 <= start
360→      invariant start + maxLength <= n
361→      invariant maxLength >= 1
362→      invariant IsPalindrome(s[start..start+maxLength])
363→      invariant 0 < i < n ==> s[i-1] != s[i]  // run doesn't extend left of i
364→      invariant forall st, len {:trigger PalindromicSubstringAt(s, st, len)} ::
365→        0 <= st < |s| && 0 <= len <= |s| &&
366→        PalindromicSubstringAt(s, st, len) && st + len / 2 < frontier
367→        ==> len <= maxLength
368→    {
369→        ghost var old_frontier := frontier;
370→
371→        var l := i;
372→        var r := i;
373→
374→        while r < n - 1 && s[r] == s[r + 1]
375→          invariant i <= r < n
376→          invariant l == i
377→          invariant forall k :: i <= k <= r ==> s[k] == s[i]
378→        {
379→            r := r + 1;
380→        }
381→
382→        ghost var cl := l;
383→        ghost var cr := r;
384→        assert cr == n - 1 || s[cr + 1] != s[cl];
385→        assert cl == 0 || s[cl - 1] != s[cl];
386→
387→        identicalCharsPalindrome(s, l, r);
388→
389→        i := r;
390→
391→        ghost var expDist := 0;
392→        while l > 0 && r < n - 1 && s[l - 1] == s[r + 1]
393→          invariant 0 <= l <= cl
394→          invariant cr <= r < n
395→          invariant l == cl - expDist
396→          invariant r == cr + expDist
397→          invariant IsPalindrome(s[l..r+1])
398→        {
399→            expandPalindrome(s, l, r);
400→            l := l - 1;
401→            r := r + 1;
402→            expDist := expDist + 1;
403→        }
404→
405→        ghost var d := expDist;
406→
407→        var length := r - l + 1;
408→        if length > maxLength
409→        {
410→            start := l;
411→            maxLength := length;
412→        }
413→
414→        i := i + 1;
415→        frontier := cr + 1;
416→
417→        forall st, len {:trigger PalindromicSubstringAt(s, st, len)} |
418→          0 <= st < |s| && 0 <= len <= |s| &&
419→          PalindromicSubstringAt(s, st, len) && st + len / 2 < frontier
420→          ensures len <= maxLength
421→        {
422→          if st + len / 2 < old_frontier {
423→          } else {
424→            assert cl <= st + len / 2 <= cr;
425→            if len == 0 {
426→            } else {
427→              palindromeBoundedByExpansion(s, cl, cr, d, st, len);
428→            }
429→          }
430→        }
431→    }
432→
433→    result := s[start..start + maxLength];
434→    assert IsPalindrome(result);
435→    assert SubstringAt(s, result, start);
436→
437→    forall st, len | 0 <= st < |s| && 0 <= len <= |s| && PalindromicSubstringAt(s, st, len)
438→      ensures len <= |result|
439→    {
440→      if len >= 1 {
441→        assert st + len / 2 < n;
442→        assert st + len / 2 < frontier;
443→      }
444→    }
445→}
